"use client"

import { useEffect, useState } from 'react'

type User = {
  id: number
  username: string
  email: string | null
  role: string
  status: string
  device_count: number
  created_at: string
  group_id: number | null
  group_name?: string
}

type Group = {
  id: number
  name: string
}

type Quota = {
  free_quota: number
  used_quota: number
  remaining: number
}

export default function UsersPage() {
  const [data, setData] = useState<any>(null)
  const [groups, setGroups] = useState<Group[]>([])
  const [error, setError] = useState('')
  const [busyId, setBusyId] = useState<number | null>(null)
  const [assigningUserId, setAssigningUserId] = useState<number | null>(null)
  const [quotaMap, setQuotaMap] = useState<Record<number, Quota>>({})
  const [showQuotaModal, setShowQuotaModal] = useState<number | null>(null)
  const [newQuota, setNewQuota] = useState(0)

  async function load() {
    const res = await fetch('/api/admin/users', { credentials: 'include' })
    if (!res.ok) throw new Error('加载失败')
    setData(await res.json())
  }

  async function loadGroups() {
    try {
      const res = await fetch('/api/admin/groups', { credentials: 'include' })
      if (res.ok) setGroups((await res.json()).items || [])
    } catch {}
  }

  async function loadQuotas(users: User[]) {
    const map: Record<number, Quota> = {}
    for (const u of users) {
      try {
        const res = await fetch(`/api/admin/users/${u.id}/quota`, { credentials: 'include' })
        if (res.ok) map[u.id] = await res.json()
      } catch {}
    }
    setQuotaMap(map)
  }

  useEffect(() => {
    load()
      .then(async () => {
        await loadGroups()
      })
      .catch(() => setError('暂时无法获取用户列表，请确认以 root 登录后访问。'))
  }, [])

  useEffect(() => {
    if (data?.items) loadQuotas(data.items)
  }, [data])

  async function setStatus(userId: number, status: 'active' | 'frozen') {
    setBusyId(userId)
    try {
      await fetch(`/api/admin/users/${userId}/set-status`, {
        method: 'POST', credentials: 'include', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status }),
      })
      await load()
    } finally { setBusyId(null) }
  }

  async function assignGroup(userId: number, groupId: number | null) {
    setBusyId(userId)
    try {
      await fetch(`/api/admin/users/${userId}/set-group`, {
        method: 'POST', credentials: 'include', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ group_id: groupId }),
      })
      await load()
    } finally { setBusyId(null) }
  }

  async function saveQuota(userId: number) {
    setBusyId(userId)
    try {
      await fetch(`/api/admin/users/${userId}/quota`, {
        method: 'POST', credentials: 'include', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ free_quota: newQuota }),
      })
      setShowQuotaModal(null)
      if (data?.items) loadQuotas(data.items)
    } finally { setBusyId(null) }
  }

  return (
    <div>
      <div className="header-row"><h2>用户管理</h2></div>
      <div className="table-wrap">
        {error ? <div>{error}</div> : !data ? <div>加载中…</div> : (
          <table>
            <thead><tr><th>ID</th><th>用户名</th><th>邮箱</th><th>角色</th><th>状态</th><th>分组</th><th>额度</th><th>设备数</th><th>注册时间</th><th>操作</th></tr></thead>
            <tbody>
              {data.items.map((u: User) => (
                <tr key={u.id}>
                  <td>{u.id}</td>
                  <td>{u.username}</td>
                  <td>{u.email || '-'}</td>
                  <td>{u.role}</td>
                  <td>{u.status}</td>
                  <td>
                    {assigningUserId === u.id ? (
                      <select
                        autoFocus
                        onBlur={e => { setAssigningUserId(null); assignGroup(u.id, e.target.value ? parseInt(e.target.value) : null) }}
                        defaultValue={u.group_id || ''}
                        style={{ padding: '2px 4px', fontSize: 13 }}
                      >
                        <option value="">未分组</option>
                        {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                      </select>
                    ) : (
                      <span
                        onClick={() => setAssigningUserId(u.id)}
                        style={{ cursor: 'pointer', borderBottom: '1px dashed #9ca3af', color: u.group_id ? '#111827' : '#9ca3af' }}
                      >
                        {u.group_name || '未分组'}
                      </span>
                    )}
                  </td>
                  <td>
                    <span
                      onClick={() => { setShowQuotaModal(u.id); setNewQuota(quotaMap[u.id]?.free_quota || 0) }}
                      style={{ cursor: 'pointer', borderBottom: '1px dashed #9ca3af' }}
                    >
                      {quotaMap[u.id] ? `${quotaMap[u.id].remaining}/${quotaMap[u.id].free_quota}` : '0/0'}
                    </span>
                  </td>
                  <td>{u.device_count}</td>
                  <td>{u.created_at}</td>
                  <td style={{ display: 'flex', gap: 8 }}>
                    {u.status === 'active' ? (
                      <button disabled={busyId===u.id} onClick={() => setStatus(u.id, 'frozen')}>冻结</button>
                    ) : (
                      <button disabled={busyId===u.id} onClick={() => setStatus(u.id, 'active')}>解冻</button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* 额度设置弹窗 */}
      {showQuotaModal !== null && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'rgba(0,0,0,0.5)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000,
        }}>
          <div style={{
            background: '#fff',
            padding: 24,
            borderRadius: 8,
            width: 300,
          }}>
            <h3 style={{ margin: '0 0 16px 0' }}>设置用户额度</h3>
            <div style={{ marginBottom: 8 }}>
              <label>免费额度:</label>
              <input
                type="number"
                value={newQuota}
                onChange={e => setNewQuota(parseInt(e.target.value) || 0)}
                style={{ width: '100%', marginTop: 4 }}
              />
            </div>
            <div style={{ fontSize: 12, color: '#6b7280' }}>
              已使用: {quotaMap[showQuotaModal]?.used_quota || 0}
            </div>
            <div style={{ display: 'flex', gap: 8, marginTop: 16 }}>
              <button onClick={() => saveQuota(showQuotaModal)} disabled={busyId === showQuotaModal}>
                {busyId === showQuotaModal ? '保存中...' : '保存'}
              </button>
              <button onClick={() => setShowQuotaModal(null)} style={{ background: '#6b7280' }}>
                取消
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
